const cellKey = (x: number, y: number): string => `${x},${y}`;

const survives = (alive: boolean, neighbors: number): boolean =>
  neighbors === 3 || (alive && neighbors === 2);

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = cellKey(cell[0], cell[1]);
      const prev = neighborCounts.get(k);
      neighborCounts.set(k, { cell, count: (prev?.count ?? 0) + 1 });
    }
  }

  return [...neighborCounts]
    .filter(([k, { count }]) => survives(liveSet.has(k), count))
    .map(([, { cell }]) => cell);
}

